import requests

def solve(arg1: dict) -> dict:
    if 'challengeId' in arg1:
        # Fetch scorecard details
        response = requests.get(f'https://api.example.com/scorecards/{arg1["challengeId"]}')
        if response.status_code == 200:
            return response.json()
        elif response.status_code == 404:
            return {'error': 'Scorecard not found'}

    if 'appealData' in arg1:
        # Create an appeal
        response = requests.post('https://api.example.com/appeals', json=arg1['appealData'])
        if response.status_code == 201:
            return response.json()
        elif response.status_code == 400:
            return {'error': 'Invalid appeal data'}

    if 'appealId' in arg1 and 'updateData' in arg1:
        # Update an appeal
        response = requests.put(f'https://api.example.com/appeals/{arg1["appealId"]}', json=arg1['updateData'])
        if response.status_code == 200:
            return response.json()

    return None
